class Solution:
    def distanceK(self, root, target, k):
        path = []
        def find(node):
            if node is None:
                return False
            path.append(node)
            if node is target:
                return True
            if find(node.left) or find(node.right):
                return True
            path.pop()
            return False
        find(root)
        result = []
        def collect(node, d):
            if node is None:
                return
            if d == 0:
                result.append(node.val)
                return
            collect(node.left, d - 1)
            collect(node.right, d - 1)
        n = len(path)
        for i in range(n):
            anc = path[n - 1 - i]
            if i == k:
                result.append(anc.val)
                continue
            if i > k:
                break
            remaining = k - i
            if i == 0:
                collect(anc.left, remaining - 1)
                collect(anc.right, remaining - 1)
            else:
                skip_child = path[n - i]
                for child in (anc.left, anc.right):
                    if child is not None and child is not skip_child:
                        collect(child, remaining - 1)
        return result

