class Solution:
    def distanceK(self, root, target, k):
        parent = {}
        def link(node, par):
            if node is None:
                return
            parent[node] = par
            link(node.left, node)
            link(node.right, node)
        link(root, None)
        visited = {target}
        queue = [target]
        dist = 0
        while queue and dist < k:
            nxt = []
            for node in queue:
                for nb in (node.left, node.right, parent.get(node)):
                    if nb is not None and nb not in visited:
                        visited.add(nb)
                        nxt.append(nb)
            queue = nxt
            dist += 1
        return [node.val for node in queue]

