var distanceK = function(root, target, k) {
    const parent = new Map();
    (function link(node, par) {
        if (node === null) return;
        parent.set(node, par);
        link(node.left, node);
        link(node.right, node);
    })(root, null);
    let visited = new Set([target]);
    let queue = [target];
    let dist = 0;
    while (queue.length && dist < k) {
        const nxt = [];
        for (const node of queue) {
            for (const nb of [node.left, node.right, parent.get(node) || null]) {
                if (nb !== null && nb !== undefined && !visited.has(nb)) {
                    visited.add(nb);
                    nxt.push(nb);
                }
            }
        }
        queue = nxt;
        dist++;
    }
    return queue.map(node => node.val);
};
